    "answers": [
      {
        "type": "text",
        "text": "Lorem ipsum dolor",
        "field": {
          "id": "SjgNnEde2K7D",
          "type": "short_text",
          "ref": "553b5ba8-4822-4880-9fec-6f3cec766ff0"
        }
      },
      {
